const { phone, address, zipCode, state, email } = $json.body;
const cleanPhone = phone ? phone.replace(/\D/g, '').slice(-10) : null;
const cleanZip = zipCode ? zipCode.replace(/\D/g, '').substring(0, 5) : null;
const cleanState = state ? state.toUpperCase().substring(0, 2) : null;
return { ...JSON.parse(JSON.stringify($json.body)), phone: cleanPhone, zipCode: cleanZip, state: cleanState, email: email?.toLowerCase() };

const { leadId, status, emailCount, pageViews, lastActivity } = $json.body;
const daysSinceActivity = lastActivity ? Math.floor((new Date() - new Date(lastActivity)) / (1000 * 60 * 60 * 24)) : 999;
let lifecycle = 'lead';
if (emailCount > 5) lifecycle = 'prospect';
if (status === 'customer') lifecycle = 'customer';
if (lifecycle === 'customer' && daysSinceActivity > 90) lifecycle = 'advocate';
return { leadId, currentLifecycle: lifecycle, daysSinceActivity, signals: {emailCount, pageViews}, nextStage: lifecycle };

const { leadId, activities } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const timeline = (activities || []).map((a, i) => ({id: i, timestamp: a.timestamp, type: a.type, description: a.description})).sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
return { leadId, timeline, totalActivities: timeline.length, lastActivity: timeline[0] || null };

const { leadId, email, serviceType, behavior, source, quality } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const tags = [];
if (serviceType) tags.push(serviceType);
if (quality === 'high') tags.push('high_quality');
if (source) tags.push(source);
if (behavior?.includes('urgent')) tags.push('urgent');
if (behavior?.includes('engaged')) tags.push('engaged');
tags.push(`lead_source_${source}`);
return { leadId, email, autoTags: tags, tagCount: tags.length };

const { leadId1, leadId2, email1, email2, phone1, phone2 } = $json.body;
if (!leadId1 || !leadId2) throw new Error('Missing leadIds');
const scoreMatch = (email1 && email1.toLowerCase() === email2.toLowerCase()) ? 100 : (phone1 && phone1 === phone2) ? 95 : 0;
return { primary: leadId1, duplicate: leadId2, matchScore: scoreMatch, shouldMerge: scoreMatch > 80, mergeStrategy: scoreMatch === 100 ? 'email_match' : 'phone_match' };

const { leadId, lastActivityDate } = $json.body;
const daysSinceActivity = lastActivityDate ? Math.floor((new Date() - new Date(lastActivityDate)) / (1000 * 60 * 60 * 24)) : 999;
const isStale = daysSinceActivity > 180;
return { leadId, daysSinceActivity, isStale, dataDecayLevel: daysSinceActivity > 180 ? 'critical' : daysSinceActivity > 90 ? 'warning' : 'healthy', flagForCleanup: isStale };

const { leadId, totalRevenue, orderCount, averageOrderValue, lastPurchaseDate } = $json.body;
let vipScore = 0;
vipScore += (totalRevenue > 5000 ? 40 : totalRevenue > 2000 ? 25 : 10);
vipScore += (orderCount > 10 ? 40 : orderCount > 5 ? 25 : 10);
vipScore += (averageOrderValue > 500 ? 20 : 10);
const isVip = vipScore > 60;
return { leadId, vipScore, isVip, tier: isVip ? 'vip' : 'regular', metrics: {totalRevenue, orderCount, averageOrderValue}, lastPurchase: lastPurchaseDate };

const { leadId, email, externalCrm } = $json.body;
if (!leadId || !externalCrm) throw new Error('Missing data');
return { leadId, email, crmSystem: externalCrm, syncDirection: 'bidirectional', lastSync: new Date().toISOString(), status: 'pending' };

const { leadId, email, birthDate, anniversaryDate } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const today = new Date();
const upcomingDays = 30;
const events = [];
if (birthDate) {
  const bd = new Date(birthDate);
  const upcoming = new Date(today.getFullYear(), bd.getMonth(), bd.getDate());
  if (upcoming < today) upcoming.setFullYear(upcoming.getFullYear() + 1);
  const daysUntil = Math.floor((upcoming - today) / (1000 * 60 * 60 * 24));
  if (daysUntil <= upcomingDays && daysUntil >= 0) events.push({type: 'birthday', date: upcoming, daysUntil});
}
if (anniversaryDate) {
  const ann = new Date(anniversaryDate);
  const upcoming = new Date(today.getFullYear(), ann.getMonth(), ann.getDate());
  if (upcoming < today) upcoming.setFullYear(upcoming.getFullYear() + 1);
  const daysUntil = Math.floor((upcoming - today) / (1000 * 60 * 60 * 24));
  if (daysUntil <= upcomingDays && daysUntil >= 0) events.push({type: 'anniversary', date: upcoming, daysUntil});
}
return { leadId, email, upcomingEvents: events, shouldNotify: events.length > 0 };

const { leadId, email, phone, address, firstName, lastName } = $json.body;
if (!leadId) throw new Error('Missing leadId');
const missing = [];
if (!email) missing.push('email');
if (!phone) missing.push('phone');
if (!address) missing.push('address');
if (!firstName) missing.push('firstName');
if (!lastName) missing.push('lastName');
const completeness = Math.round(((5 - missing.length) / 5) * 100);
return { leadId, completeness, score: completeness, missing, hasCriticalGaps: missing.length >= 2, flagForEnrichment: completeness < 60 };
